#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, D, S, C;
        scanf("%lld %lld %lld %lld", &L, &D, &S, &C);
        for (int i = 0; i < D; i++) {
            S = S * (C + 1);
        }
        if (S >= L) {
            printf("ALIVE AND KICKING\n");
        } else {
            printf("DEAD AND ROTTING\n");
        }
    }
    return 0;
}

